from functools import lru_cache

@lru_cache(maxsize=None)
def fib(n: int) -> int:
    # Base cases
    if n == 0:
        return 0
    if n == 1:
        return 1

    # Recursive step with memoization
    return fib(n - 1) + fib(n - 2)

